mapper.select:
SELECT c.id, c.teacher_id, c.course_code, c.course_name, c.course_cover, c.short_description, c.full_description, c.credit, c.category_id , c.level, c.total_hours , c.price, c.status, c.is_free, c.max_students, c.current_students, c.view_count, c.like_count, c.rating, c.rating_count, c.published_time , c.created_time, c.updated_time, cc.category_name, COALESCE(tu.real_name, tu.nickname, tu.username) AS teacher_name FROM course c LEFT JOIN course_category cc ON c.category_id = cc.id LEFT JOIN education_user_db.teachers tt ON c.teacher_id = tt.id LEFT JOIN education_user_db.teachers tu2 ON c.teacher_id = tu2.user_id LEFT JOIN education_user_db.users tu ON tu.id = COALESCE(tt.user_id, tu2.user_id)
AND c.course_code = #{q.courseCode}
AND c.course_name LIKE CONCAT('%', #{q.courseName}, '%')
AND c.category_id = #{q.categoryId}
AND c.teacher_id = #{q.teacherId}
AND c.status = #{q.status}
AND ( c.course_name LIKE CONCAT('%', #{q.keyword}, '%') OR c.short_description LIKE CONCAT('%', #{q.keyword}, '%') OR COALESCE(tu.real_name, tu.nickname, tu.username) LIKE CONCAT('%', #{q.keyword}, '%') )
AND c.is_free = #{q.isFree}
AND c.published_time BETWEEN #{q.beginTime} AND #{q.endTime}
ORDER BY
c.view_count
c.rating
c.published_time
c.published_time
ASC
DESC
c.published_time DESC
